import React, { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import Layout from "../Layout";
import useFetch from "../../hooks/useFetch";
import {
  adminCategoriesList,
  adminCategoryDetails,
  adminCreateCategory,
  adminUpdateCategory,
} from "../../api/categories";
import {
  SOMETHING_WENT_WRONG,
  showSnackbar,
  errorType,
  ok,
} from "../../../utils";

const CategoryForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEdit = !!id;
  const [saving, setSaving] = useState(false);

  const [form, setForm] = useState({
    name: "",
    parent_id: "",
  });

  const { apiData: categoriesData } = useFetch(adminCategoriesList, {});
  const { apiData: categoryData } = useFetch(
    isEdit ? adminCategoryDetails : null,
    isEdit ? id : null,
  );

  const categories =
    categoriesData?.categories?.filter((c) => c.id !== Number(id)) || [];

  // Pre-fill on edit
  useEffect(() => {
    if (!isEdit || !categoryData?.category) return;
    const c = categoryData.category;
    setForm({
      name: c.name || "",
      parent_id: c.parent_id || "",
    });
  }, [categoryData]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      if (isEdit) {
        await adminUpdateCategory(id, form);
      } else {
        await adminCreateCategory(form);
      }
      showSnackbar("Category saved!", ok);
      navigate("/categories");
    } catch (e) {
      showSnackbar(e || SOMETHING_WENT_WRONG, errorType);
    } finally {
      setSaving(false);
    }
  };

  return (
    <Layout>
      <>
        <h1 className="h3 mb-4 text-gray-800">
          {isEdit ? "Edit Category" : "Create Category"}
        </h1>

        <div className="card shadow mb-4">
          <div className="card-body">
            <form onSubmit={handleSubmit}>
              {/* Name */}
              <div className="form-group">
                <label>Name *</label>
                <input
                  name="name"
                  value={form.name}
                  onChange={handleChange}
                  required
                  className="form-control bg-light border-2 small"
                  placeholder="Category name"
                />
              </div>

              {/* Parent Category */}
              <div className="form-group">
                <label>Parent Category</label>
                <select
                  name="parent_id"
                  value={form.parent_id}
                  onChange={handleChange}
                  className="form-control bg-light border-2 small"
                >
                  <option value="">No parent (top level)</option>
                  {categories.map((c) => (
                    <option key={c.id} value={c.id}>
                      {c.name}
                    </option>
                  ))}
                </select>
              </div>

              <button
                type="submit"
                disabled={saving || !form.name.trim()}
                className="btn btn-primary"
              >
                {saving
                  ? "Saving..."
                  : isEdit
                    ? "Update Category"
                    : "Create Category"}
              </button>
            </form>
          </div>
        </div>
      </>
    </Layout>
  );
};

export default CategoryForm;
